    private static final long NEG_INF = Long.MIN_VALUE / 2;
    private static final int MAX_VAL = 100000;

    // Node structure for the Persistent Segment Tree
    static class Node {
        long maxVal;
        Node left, right;

        Node() {
            this.maxVal = NEG_INF;
            this.left = null;
            this.right = null;
        }
    }

    /**
     * Updates the segment tree persistently at a given position (value v) 
     * with a new maximum value (val).
     * 
     * @param prev The root of the previous version.
     * @param start The current segment range start.
     * @param end The current segment range end.
     * @param v The value index to update (nums[i]).
     * @param val The new max value to store (DP[i]).
     * @return The root of the new version.
     */
    private static Node update(Node prev, int start, int end, int v, long val) {
        Node current = new Node();
        if (prev != null) {
            current.left = prev.left;
            current.right = prev.right;
            current.maxVal = prev.maxVal;
        }

        if (start == end) {
            current.maxVal = Math.max(current.maxVal, val);
            return current;
        }

        int mid = start + (end - start) / 2;

        if (v <= mid) {
            // Recurse left
            Node prevLeft = (prev != null && prev.left != null) ? prev.left : null;
            current.left = update(prevLeft, start, mid, v, val);
        } else {
            // Recurse right
            Node prevRight = (prev != null && prev.right != null) ? prev.right : null;
            current.right = update(prevRight, mid + 1, end, v, val);
        }

        // Update maxVal based on children
        long leftMax = (current.left != null) ? current.left.maxVal : NEG_INF;
        long rightMax = (current.right != null) ? current.right.maxVal : NEG_INF;
        current.maxVal = Math.max(leftMax, rightMax);

        return current;
    }

    /**
     * Queries the maximum value in the segment tree version rooted at 'root' 
     * over the range [qStart, qEnd].
     */
    private static long query(Node root, int start, int end, int qStart, int qEnd) {
        if (root == null || qStart > end || qEnd < start || qStart > qEnd) {
            return NEG_INF;
        }

        if (qStart <= start && end <= qEnd) {
            return root.maxVal;
        }

        int mid = start + (end - start) / 2;

        long leftMax = query(root.left, start, mid, qStart, qEnd);
        long rightMax = query(root.right, mid + 1, end, qStart, qEnd);

        return Math.max(leftMax, rightMax);
    }


