        // Root[i] stores the state after processing index i
        Node[] rootUp = new Node[N];
        Node[] rootDown = new Node[N];

        // Base roots (representing state before index 0, all values NEG_INF)
        Node emptyRoot = new Node();
        Node[] rootUpPrev = new Node[N];
        Node[] rootDownPrev = new Node[N];

        for(int i=0; i<N; i++){
            rootUpPrev[i] = emptyRoot;
            rootDownPrev[i] = emptyRoot;
        }

        long maxScore = 0;

        for (int i = 0; i < N; i++) {
            long currentVal = nums[i];

            // Base case: Sequence of length 1
            dpUp[i] = currentVal;
            dpDown[i] = currentVal;

            int L = i - (int)k; // Predecessor index limit

            if (L >= 0) {
                // 1. Calculate DP_UP[i]: requires previous state to be DOWN (i.e., nums[j] < nums[i])
