                // Query PST_UP at version L, looking for values [nums[i]+1, MAX_VAL]
                Node prevUpRoot = rootUp[L];
                long M_UP = query(prevUpRoot, 1, MAX_VAL, (int)currentVal + 1, MAX_VAL);

                if (M_UP != NEG_INF) {
                    dpDown[i] = Math.max(dpDown[i], currentVal + M_UP);
                }
            }

            // Update overall maximum score
            maxScore = Math.max(maxScore, dpUp[i]);
            maxScore = Math.max(maxScore, dpDown[i]);

            // Update PSTs for index i
